+            0_u8.hash(hasher);
+            true
+        }
+        TraceData::Task { task, region } => {
+            1_u8.hash(hasher);
+            task.hash(hasher);
+            region.hash(hasher);
+            true
+        }
+        TraceData::Region { region, parent } => {
+            2_u8.hash(hasher);
+            region.hash(hasher);
+            parent.hash(hasher);
+            true
+        }
+        TraceData::Obligation {
+            obligation,
+            task,
+            region,
+            kind,
+            state,
+            duration_ns,
+            abort_reason,
+        } => {
+            3_u8.hash(hasher);
+            obligation.hash(hasher);
+            task.hash(hasher);
+            region.hash(hasher);
+            kind.hash(hasher);
+            hash_obligation_state(hasher, *state);
+            duration_ns.hash(hasher);
+            hash_obligation_abort_reason(hasher, *abort_reason);
+            true
+        }
+        TraceData::Cancel {
+            task,
+            region,
+            reason,
+        } => {
+            4_u8.hash(hasher);
+            task.hash(hasher);
+            region.hash(hasher);
+            hash_cancel_reason(hasher, reason);
+            true
+        }
+        TraceData::Worker {
+            worker_id,
+            job_id,
+            decision_seq,
+            replay_hash,
+            task,
+            region,
+            obligation,
+        } => {
+            5_u8.hash(hasher);
+            worker_id.hash(hasher);
+            job_id.hash(hasher);
+            decision_seq.hash(hasher);
+            replay_hash.hash(hasher);
+            task.hash(hasher);
+            region.hash(hasher);
+            obligation.hash(hasher);
+            true
+        }
+        TraceData::RegionCancel { region, reason } => {
+            6_u8.hash(hasher);
+            region.hash(hasher);
+            hash_cancel_reason(hasher, reason);
+            true
+        }
+        _ => false,
+    }
+}
